#include <stdio.h>

int main() {
    int i, j;
    for (i = 1; i <= 9; i++) {
        for (j = 1; j <= i; j++) {
            printf("%d*%d=%-2d ", i, j, i * j);
        }
        printf("\n");
    }
    return 0;
}

#include <stdio.h>

int main() {
    int i, j;
    for (i = 1; i <= 9; i++) {
        for (j = 1; j <= i; j++) {
            if (i * j > 20) {
                break; // 跳出内层循环
            }
            printf("%d*%d=%-2d ", i, j, i * j);
        }
        printf("\n");
    }
    return 0;
}

#include <stdio.h>

int main() {
    int i = 1, j;
    while (i <= 9) {
        j = 1; // 重置内层循环变量
        while (j <= i) {
            printf("%d*%d=%-2d ", i, j, i * j);
            j++; // 更新变量避免死循环
        }
        printf("\n");
        i++; // 更新变量避免死循环
    }
    return 0;
}

